import{_ as n,C as i,o as t,c as s,a4 as o,b as d,w as r,a as c,E as l,a5 as u}from"./chunks/framework.BZxhJ0Uw.js";const v=JSON.parse('{"title":"System Overview","description":"","frontmatter":{},"headers":[],"relativePath":"reference/architecture/system-overview.md","filePath":"reference/architecture/system-overview.md"}'),h={name:"reference/architecture/system-overview.md"};function p(m,e,g,y,f,b){const a=i("Mermaid");return t(),s("div",null,[e[1]||(e[1]=o('<h1 id="system-overview" tabindex="-1">System Overview <a class="header-anchor" href="#system-overview" aria-label="Permalink to &quot;System Overview&quot;">​</a></h1><blockquote><p><strong>Last Updated</strong>: 2026-06-28</p></blockquote><h2 id="architecture-style" tabindex="-1">Architecture Style <a class="header-anchor" href="#architecture-style" aria-label="Permalink to &quot;Architecture Style&quot;">​</a></h2><p><code>@jsvision/core</code> is a <strong>foundation-first, layered library</strong> with a single public entry point (<code>src/engine/index.ts</code>). Each subsystem is a self-contained module folder under <code>src/engine/**</code> that re-exports its public surface through the root index; consumers import everything from <code>@jsvision/core</code> and never reach into a module&#39;s internals.</p><p>The style is deliberately <strong>pure-core / thin-shell</strong>: rendering, decoding, colour encoding, and capability resolution are pure functions over plain data, while the only stateful, side-effecting layer (the host) is isolated behind an injectable <code>RuntimeAdapter</code>. This was chosen so the entire engine is testable without a real terminal — golden-screen tests drive a headless emulator, restore-on-exit is proven with a fake adapter, and decoding is fuzzed as a pure transform. See <a href="/jsvision/pr-preview/pr-54/reference/decisions/ADR-003-pure-core-injectable-seams.html">ADR-003</a> and <a href="/jsvision/pr-preview/pr-54/reference/decisions/ADR-004-no-node-pty.html">ADR-004</a>.</p><h2 id="component-architecture" tabindex="-1">Component Architecture <a class="header-anchor" href="#component-architecture" aria-label="Permalink to &quot;Component Architecture&quot;">​</a></h2>',6)),(t(),d(u,null,{default:r(()=>[l(a,{id:"mermaid-20",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20Public%0A%20%20%20%20%20%20%20%20Index%5Bindex.ts%20%E2%80%94%20single%20entry%20point%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Pure%20core%0A%20%20%20%20%20%20%20%20Capability%5Bcapability%2F%20%E2%80%94%20RD-02%20detection%5D%0A%20%20%20%20%20%20%20%20Input%5Binput%2F%20%E2%80%94%20RD-06%20decoder%5D%0A%20%20%20%20%20%20%20%20Render%5Brender%2F%20%E2%80%94%20RD-04%20buffer%20%2B%20serialize%5D%0A%20%20%20%20%20%20%20%20Color%5Bcolor%2F%20%E2%80%94%20RD-05%20encode%2Fdownsample%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Side-effecting%20shell%0A%20%20%20%20%20%20%20%20Host%5Bhost%2F%20%E2%80%94%20RD-07%20tty%20host%20%2B%20RuntimeAdapter%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Cross-cutting%0A%20%20%20%20%20%20%20%20Safety%5Bsafety%2F%20%E2%80%94%20RD-08%20essentials%2C%20sanitize%2C%20errors%5D%0A%20%20%20%20end%0A%0A%20%20%20%20Index%20--%3E%20Capability%20%26%20Input%20%26%20Render%20%26%20Color%20%26%20Host%20%26%20Safety%0A%20%20%20%20Render%20--%3E%20Color%0A%20%20%20%20Render%20--%3E%20Safety%0A%20%20%20%20Host%20--%3E%20Capability%0A%20%20%20%20Host%20--%3E%20Input%0A%20%20%20%20Host%20--%3E%20Render%0A%20%20%20%20Capability%20--%3E%20Safety%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="component-responsibilities" tabindex="-1">Component Responsibilities <a class="header-anchor" href="#component-responsibilities" aria-label="Permalink to &quot;Component Responsibilities&quot;">​</a></h2><h3 id="capability-detection-capability-rd-02" tabindex="-1">Capability detection (<code>capability/</code>, RD-02) <a class="header-anchor" href="#capability-detection-capability-rd-02" aria-label="Permalink to &quot;Capability detection (`capability/`, RD-02)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Resolve a frozen <code>CapabilityProfile</code> (colour depth, glyphs, mouse, keyboard, OSC, sync) from environment, a static table, and an optional bounded live terminal query. Doubles as runtime auto-configuration (<a href="/jsvision/pr-preview/pr-54/reference/decisions/ADR-002-capability-auto-config.html">ADR-002</a>).</li><li><strong>Inputs</strong>: <code>env</code>, <code>platform</code>, optional <code>TerminalQuery</code> seam, <code>timeoutMs</code>.</li><li><strong>Outputs</strong>: <code>resolveCapabilities</code> (sync) / <code>resolveCapabilitiesAsync</code> (with layer-2 query).</li><li><strong>Dependencies</strong>: safety (sanitize/redaction); the host supplies the real <code>TerminalQuery</code>.</li></ul><h3 id="input-decoder-input-rd-06" tabindex="-1">Input decoder (<code>input/</code>, RD-06) <a class="header-anchor" href="#input-decoder-input-rd-06" aria-label="Permalink to &quot;Input decoder (`input/`, RD-06)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Turn raw input bytes into typed <code>InputEvent</code>s (keys, mouse, wheel, paste, focus, query responses) as a pure transform with a small carry buffer.</li><li><strong>Inputs</strong>: byte chunks + <code>DecoderState</code>.</li><li><strong>Outputs</strong>: <code>decode</code> / <code>flush</code> / <code>createDecoderState</code> / <code>createKeymap</code>.</li><li><strong>Dependencies</strong>: none (pure); bounded buffers (paste/response caps).</li></ul><h3 id="rendering-engine-render-rd-04" tabindex="-1">Rendering engine (<code>render/</code>, RD-04) <a class="header-anchor" href="#rendering-engine-render-rd-04" aria-label="Permalink to &quot;Rendering engine (`render/`, RD-04)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: A width-correct <code>ScreenBuffer</code> apps draw into, and a pure <code>serialize</code> that emits the minimal ANSI to turn the previous frame into the current one (damage diff). Bytes are proportional to damage.</li><li><strong>Inputs</strong>: <code>ScreenBuffer</code> (current/previous) + <code>RenderOptions</code> (caps + optional encoder).</li><li><strong>Outputs</strong>: <code>serialize</code>, <code>ScreenBuffer</code>, glyph fallback, cursor/OSC helpers.</li><li><strong>Dependencies</strong>: colour (default <code>StyleEncoder</code>), safety (<code>sanitize</code>).</li></ul><h3 id="color-styling-color-rd-05" tabindex="-1">Color &amp; styling (<code>color/</code>, RD-05) <a class="header-anchor" href="#color-styling-color-rd-05" aria-label="Permalink to &quot;Color &amp; styling (`color/`, RD-05)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Depth-aware SGR encoding — downsample truecolor→256→16→mono via a redmean nearest-colour search; merge attrs + fg + bg into one SGR. It is the default encoder <code>serialize</code> injects (<a href="/jsvision/pr-preview/pr-54/reference/decisions/ADR-003-pure-core-injectable-seams.html">ADR-006 references the seam</a>).</li><li><strong>Outputs</strong>: <code>encode</code>, <code>encodeStyle</code>, <code>nearest256</code>, <code>nearest16</code>, <code>PALETTE</code>, <code>defaultTheme</code>.</li></ul><h3 id="host-lifecycle-host-rd-07" tabindex="-1">Host &amp; lifecycle (<code>host/</code>, RD-07) <a class="header-anchor" href="#host-lifecycle-host-rd-07" aria-label="Permalink to &quot;Host &amp; lifecycle (`host/`, RD-07)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: The only stateful subsystem — raw mode, alt-screen entry/exit, signal handling, suspend/resume, and <strong>guaranteed restore on every exit path</strong>, all behind an injectable <code>RuntimeAdapter</code>. Also hosts the real tty-backed <code>createTerminalQuery</code> (RD-03) that completes RD-02&#39;s layer-2 wiring.</li><li><strong>Outputs</strong>: <code>createHost</code>, <code>detectTty</code>, <code>createTerminalQuery</code>.</li></ul><h3 id="safety-safety-rd-08" tabindex="-1">Safety (<code>safety/</code>, RD-08) <a class="header-anchor" href="#safety-safety-rd-08" aria-label="Permalink to &quot;Safety (`safety/`, RD-08)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: The essentials gate (<code>evaluateEssentials</code>/<code>assertEssentials</code>), the screen-safe logger, <code>redactEvent</code>/<code>dumpCaps</code>, the typed <code>TuiError</code> model, and the canonical <code>sanitize</code> injection boundary (<a href="/jsvision/pr-preview/pr-54/reference/decisions/ADR-005-sanitize-boundary.html">ADR-005</a>).</li></ul><h2 id="communication-patterns" tabindex="-1">Communication Patterns <a class="header-anchor" href="#communication-patterns" aria-label="Permalink to &quot;Communication Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>From</th><th>To</th><th>Mechanism</th><th>Pattern</th><th>Notes</th></tr></thead><tbody><tr><td>App</td><td>render</td><td><code>serialize(current, previous, opts)</code></td><td>Sync, pure</td><td>Host holds the previous frame</td></tr><tr><td>Host</td><td>capability</td><td><code>TerminalQuery</code> seam</td><td>Async, bounded</td><td>Layer-2 query, <code>timeoutMs</code>-bounded</td></tr><tr><td>Render</td><td>color</td><td><code>StyleEncoder</code> injection</td><td>Sync, pure</td><td>Default = RD-05 <code>encodeStyle</code></td></tr><tr><td>Host</td><td>runtime</td><td><code>RuntimeAdapter</code> injection</td><td>Side-effecting</td><td>The single I/O seam</td></tr></tbody></table><h2 id="cross-cutting-concerns" tabindex="-1">Cross-Cutting Concerns <a class="header-anchor" href="#cross-cutting-concerns" aria-label="Permalink to &quot;Cross-Cutting Concerns&quot;">​</a></h2><ul><li><strong>Auto-configuration</strong>: capability detection adapts output to the terminal with zero app configuration.</li><li><strong>Logging</strong>: screen-safe logger never corrupts the alt-screen; redaction strips secrets/PII before any log.</li><li><strong>Error handling</strong>: a typed <code>TuiError</code> hierarchy; the render path degrades crash-safe rather than throwing on bad cell data.</li><li><strong>Restore guarantee</strong>: the host restores the terminal on normal exit, throw, <code>SIGINT</code>/<code>SIGTERM</code>/<code>SIGHUP</code>, proven by the RD-09 Tier-3 e2e.</li></ul>',17))])}const R=n(h,[["render",p]]);export{v as __pageData,R as default};
